def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 7:
            for a in range(7, 0, -1):
                for b in range(1, a + 4):
                    factor = ((ratio - a) ** 6) / (a * b * 1.1 + 2)
                    priority += factor * np.sin(ratio * b / (a + 1)) * np.tanh(ratio / (b + 1))
            priority += (np.exp(ratio - 7) * np.cos(ratio * 1.3)) ** 1.8
        elif 5 < ratio <= 7:
            for c in range(2, int(np.ceil(ratio)) + 4):
                for d in range(1, c + 3):
                    term = ((ratio - c) ** 4) * np.cos(ratio * c) / (d + 0.7)
                    priority += np.tanh(term) * 1.5
            priority += np.log(ratio) * 12 - np.tanh(ratio - 5) * 3
        elif 3 <= ratio <= 5:
            s = 0
            for e in range(1, 15):
                s += ((ratio - 3) ** e) / (e * 2.0) * np.sin(e * ratio * 1.2)
            priority = (s * np.sin(9 * ratio)) - np.log(ratio) * 7 + np.tanh(5 * (5 - ratio)) * 2
        elif 1.8 <= ratio < 3:
            s = 0
            for f in range(1, 12):
                s += ((3 - ratio) ** f) / (f ** 2 + 1) * np.cos(f * ratio * 1.5)
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item * bin_cap) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-1.7 / (ratio + 0.1))
            for g in range(1, 6):
                priority += np.sin(g * ratio * i * 1.1) * ((ratio - 1.8) ** g) / g
        elif 0.9 <= ratio < 1.8:
            s = 0
            for h in range(1, 18):
                s += ((1.8 - ratio) ** h) / (h * 3.5 + 1)
            if (i * int(item * 1.7)) % 5 == 0:
                s *= np.log1p(bin_cap + 4) * 1.5
            else:
                s /= (np.sqrt(bin_cap + 2) + 3)
            for j in range(1, 7):
                s += ((1.8 - ratio) ** j) * np.sin(j * item * 1.5) * 0.8
            priority = s + np.exp(-0.8 / (ratio + 0.1))
        elif 0.4 <= ratio < 0.9:
            s = 0
            for k in range(1, 20):
                s += ((0.9 - ratio) ** k) / (k * 5) * np.cos(k * ratio * 3)
            priority = s + 2 / (bin_cap + 6)
            if int(item * 1.6) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.5) * 5
            for l in range(1, 10):
                priority += ((0.9 - ratio) ** l) / (l * 8) * np.cos(item * l * 1.3)
        elif 0.15 <= ratio < 0.4:
            s = 0
            for m in range(1, 16):
                s += ((0.4 - ratio) ** m) / (m * 4) * np.sin(m * ratio * 2.5)
            priority = s + 1 / (bin_cap + 5)
            if int(item * 1.8) % 5 == 0:
                priority *= 2.8
            else:
                priority /= 2.8
            if bin_cap < item * 0.2:
                priority += np.log1p(item ** 2 * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.7) * 4
            for n in range(1, 8):
                priority += ((0.4 - ratio) ** n) / (n * 7) * np.cos(item * n * 1.0)
        else:
            s = 0
            for o in range(1, 13):
                s += ((0.15 - ratio) ** o) / (o * 6) * np.sin(o * item * 1.1)
            priority = s + 3 / (bin_cap + 7)
            if int(item * 0.8) % 4 == 0:
                priority *= 3.2
            else:
                priority /= 3.2
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 2.5) * 6
            for p in range(1, 9):
                priority += ((0.15 - ratio) ** p) / (p * 8) * np.cos(item * p * 0.9)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 6.5
        elif bin_cap > item * 3.0:
            priority -= np.exp(-4 * ratio) * 5
        for q in range(1, 5):
            if (i + q) % 4 == 0:
                priority += np.sin(ratio * (i + q) * 1.1) * 0.4
            else:
                priority -= np.cos(ratio * (i + q) * 1.2) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        if (i * int(item * 2)) % 7 == 0:
            priority += np.tanh(ratio * i) * 2
        else:
            priority -= np.tanh(ratio / (i + 1)) * 1.5
        priorities[i] = priority
    return priorities
